# Vehicle module - defines the vehicle hierarchy with base classes and interfaces

interface IMovable:
    def move(self) -> str

interface IFuelEfficient:
    def calculate_efficiency(self) -> float

@abstract
class Vehicle:
    _name: str
    _speed: int
    _capacity: int

    def __init__(self, name: str, speed: int, capacity: int):
        self._name = name
        self._speed = speed
        self._capacity = capacity

    @virtual
    def get_name(self) -> str:
        return self._name

    @virtual
    def get_speed(self) -> int:
        return self._speed

    @virtual
    def get_capacity(self) -> int:
        return self._capacity

    @virtual
    def describe(self) -> str:
        return "Vehicle: " + self._name + " with speed " + str(self._speed)

    @virtual
    def calculate_range(self) -> int:
        return self._speed * 10

    @abstract
    def fuel_type(self) -> str: ...

class ElectricVehicle(Vehicle, IFuelEfficient):
    _battery_capacity: float

    def __init__(self, name: str, speed: int, capacity: int, battery: float):
        super().__init__(name, speed, capacity)
        self._battery_capacity = battery

    @override
    def get_name(self) -> str:
        return self._name

    @override
    def describe(self) -> str:
        return "Electric: " + self.get_name() + ", " + str(self._battery_capacity) + "kWh battery"

    @override
    def fuel_type(self) -> str:
        return "Electricity"

    @override
    def calculate_efficiency(self) -> float:
        return self._battery_capacity / float(self._capacity)

class GasVehicle(Vehicle, IFuelEfficient):
    _tank_size: float
    _mpg: float

    def __init__(self, name: str, speed: int, capacity: int, tank: float, mpg: float):
        super().__init__(name, speed, capacity)
        self._tank_size = tank
        self._mpg = mpg

    @override
    def get_name(self) -> str:
        return self._name

    @override
    def fuel_type(self) -> str:
        return "Gasoline"

    @override
    def calculate_efficiency(self) -> float:
        return self._mpg

type VehicleFilter = (Vehicle) -> bool

