# Utils module - helper functions and formatters for vehicle fleet management

from inventory import Priority

def format_currency(amount: float) -> str:
    return "$" + str(round(amount, 2))

def calculate_discount(base_price: float, rate: float) -> float:
    return base_price * (1.0 - rate)

def create_id(prefix: str, number: int) -> str:
    prefix_str: str = prefix
    num_str: str = str(number)
    if number < 10:
        num_str = "000" + num_str
    elif number < 100:
        num_str = "00" + num_str
    elif number < 1000:
        num_str = "0" + num_str
    return prefix_str + "-" + num_str

def sum_priorities(items: list[Priority]) -> int:
    total: int = 0
    for p in items:
        total = total + p.value
    return total

class Logger:
    @static
    _logs: list[str] = []

    @static
    def log(message: str) -> None:
        Logger._logs.append(message)

    @static
    def get_all() -> list[str]:
        return Logger._logs.copy()
